public class Solution {
    private static final int FEBRUARY = 2;

    int numberOfDays(int year, int month) {
        if (month != FEBRUARY && isLeapYear(year)) return getMonthLength(month);
        if (isFebruary(year))
            throw new IllegalArgumentException("Invalid February days: " + month);

        return -1; // This line should not be reached
    }

    private boolean isLeapYear(int year) {
        return ((year % 4 == 0 && year % 100 != 0) || (year % 400 == 0));
    }

    private int getMonthLength(int month) {
        switch (month) {
            case 4:
            case 6:
            case 9:
            case 11:
                return 30;
            default:
                return 31;
        }
    }
}

