public class Solution {
    public boolean isArmstrong(int n) {
        int power_sum = 0;
        int original = n;
        int k = String.valueOf(n).length();
        while (n > 0) {
            int digit = n % 10;
            power_sum += Math.pow(digit, k);
            n /= 10;
        }
        return power_sum == original;
    }
}

