public class Solution {
    public int movesToMakeZigzag(int[] nums) {
        if (nums == null || nums.length < 2) return 0;

        boolean isEven = false; // Assume the first element starts as even
        int totalMoves = 0;

        for (int i = 1; i < nums.length; i++) {
            int left = isEven ? Integer.MAX_VALUE : nums[i - 1];
            int right = !isEven ? Integer.MAX_VALUE : nums[i + 1];

            if (!isValid(nums[i], left, right)) {
                totalMoves += Math.abs(left) + Math.abs(right);
            }

            // Toggle the current state
            isEven = !isEven;
        }

        return totalMoves;
    }

    private boolean isValid(int num, int left, int right) {
        if (num >= Math.min(left, right)) return false;
        return true;
    }
}

