    public boolean btree_Game_Winning_Move(TreeNode root, int n, int x) {
        TreeNode xNode = findNode(root, x);
        int leftNodes = countNodes(xNode.left);
        int rightNodes = countNodes(xNode.right);
        int parentNodes = n - leftNodes - rightNodes - 1;

        return Math.max(Math.max(leftNodes, rightNodes), parentNodes) > n / 2;
    }

    public int countNodes(TreeNode node) {
        if (node == null) return 0;
        return countNodes(node.left) + countNodes(node.right) + 1;
    }

    public TreeNode findNode(TreeNode node, int x) {
        if (node == null) return null;
        if (node.val == x) return node;
        TreeNode leftSearch = findNode(node.left, x);
        if (leftSearch != null) return leftSearch;
        return findNode(node.right, x);
    }
}

