public class Solution {
    public int nthUglyNumber(int n, int a, int b, int c) {
        long left = 1, right = (long) 2e9;

        while (left < right) {
            long mid = left + (right - left) / 2;

            // Inline gcd calculation
            long count = mid / a + mid / b + mid / c 
                        - mid / ((a * b) / gcd(a, b)) 
                        - mid / ((a * c) / gcd(a, c))
                        - mid / ((b * c) / gcd(b, c))
                        + mid / (((a * b) * c) / (gcd(a, b) * gcd(b, c)));

            if (count < n) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }

        return (int) left;
    }

    private long gcd(long a, long b) {
        while (b != 0) {
            long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}

