class Solution {
    public String smallestStringWithSwaps(String s, int[][] pairs) {
        int n = s.length();
        int[] p = new int[n];

        for (int i = 0; i < n; i++) {
            p[i] = i;
        }

        // Merge the three loops into a single pass
        for (int[] pair : pairs) {
            union(pair[0], pair[1], p);
        }

        Map<Integer, PriorityQueue<Character>> groups = new HashMap<>();
        for (int i = 0; i < n; i++) {
            int root = find(i, p);
            if (!groups.containsKey(root)) {
                groups.put(root, new PriorityQueue<>());
            }
            groups.get(root).add(s.charAt(i));
        }

        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < n; i++) {
            int root = find(i, p);
            char c = groups.get(root).poll();
            sb.append(c);
        }

        return sb.toString();
    }

    private void union(int x, int y, int[] p) {
        if (p[x] != x) {
            p[x] = find(p[x], p);
        }
        if (p[y] != y) {
            p[y] = find(p[y], p);
        }
        if (find(x, p) != find(y, p)) {
            p[find(y, p)] = find(x, p);
        }
    }

    private int find(int x, int[] p) {
        if (p[x] != x) {
            p[x] = find(p[x], p);
        }

        return p[x];
    }
}

