            sb.append('!');
        }
        return sb.toString();
    }
}

public class Solution {
    public String alphabetBoardPath(String target) {

        int x = 0, y = 0;
        StringBuilder sb = new StringBuilder();

        for (char c : target.toCharArray()) {
            dx = (c - 'a') / 5;
            dy = (c - 'a') % 5;

            moveDown(dx);
            moveLeft(dy);

            sb.append('!');
        }
        return sb.toString();

    }

    private void moveDown(int steps) {
        while (x > steps) {
            x--;
            sb.append('U');
        }
    }

    private void moveLeft(int steps) {
        while (y > steps) {
            y--;
            sb.append('L');
        }
    }
}

