public class Solution {
    public int closestToTarget(int[] arr, int target) {

        int minDiff = Integer.MAX_VALUE;
        Set<Integer> prefix = new HashSet<>();

        for (int n : arr) {
            splitOperation(n, prefix);
            findMinDifference(prefix, target, minDiff);
        }
        return minDiff;
    }

    private void splitOperation(int n, Set<Integer> prefix) {
        Set<Integer> nextPrefix = new HashSet<>();

        for (int p : prefix) {
            nextPrefix.add(p & n);
        }
        nextPrefix.add(n);

        prefix.clear();
        prefix.addAll(nextPrefix);
    }

    private void findMinDifference(Set<Integer> currentPrefix, int target, int minDiff) {
        for (int p : currentPrefix) {
            minDiff = Math.min(minDiff, Math.abs(p - target));
        }
    }
}

