    public int maxNonOverlapping(int[] nums, int target) {
        Map<Integer, Integer> prefixSum = new HashMap<>();
        int sum = 0, count = 0;
        prefixSum.put(0, 0);
        for (int num : nums) {
            sum += num;
            if (prefixSum.containsKey(sum - target)) {
                count = Math.max(count, 1 + prefixSum.get(sum - target));
            }
            prefixSum.put(sum, count);
        }
        return count;
    }
}

