public class Solution {
    int longestAwesomeSubstring(String s) {
        int n = s.length();
        int maxLen = 0;
        for (int i = 0; i < n; ++i) {
            for (int j = i + 1; j <= n; ++j) {
                String substr = s.substring(i, j);
                if (isAwesome(substr)) {
                    maxLen = Math.max(maxLen, j - i);
                }
            }
        }
        return maxLen;
    }

    boolean isAwesome(String s) {
        int odd_count = 0;
        int[] freq = new int[26];
        for (char c : s.toCharArray()) {
            freq[c - 'a']++;
        }
        for (int i = 0; i < 26; i++) {
            if (freq[i] % 2 == 1) {
                odd_count++;
            }
        }
        return (odd_count <= 1);
    }
}

