public class Solution {
    int longestAwesomeSubstring(String s) {
        int n = s.length();
        int maxLen = 0;
        for (int i = 0; i < n; ++i) {
            if (!isAwesome(s.substring(i))) continue;
            maxLen = Math.max(maxLen, n - i);
        }
        return maxLen;
    }

    boolean isAwesome(String s) {
        int odd_count = 0;
        for (char c : s.toCharArray()) {
            odd_count ^= (1 << (c - 'a'));
        }
        return (odd_count == 0 || Math.abs(odd_count & ((1 << 26) - 1)) <= 1);
    }
}

